import {useContext, useEffect} from 'react';
import { ContextoGlobal } from '../../../contexts/variaveisGlobais';
import { FetchApi } from '../../../Controller/FetchApi';


const ListaDeBrinquedosNoEvento = (props) => {
    let evento = props.evento, i = 0;    
    return(
        <div className="col-md-12 brinquedosListaEventos d-flex flex-wrap">
            {evento.brinquedos.error ? 
                <div>
                    Não foi possível obter os brinquedos do evento
                </div>
                :
                evento.brinquedos.map((brinquedo)=>{
                    if(brinquedo.hasOwnProperty('error')){
                        return(
                            <div>{brinquedo.error}</div>
                        )
                    } else {
                        return(
                            <div key={i++} id="brinquedo_individual">
                                <div className="modulo_brinquedo p-2">
                                    <div className="nome_brinquedo letra_bem_pequena">{brinquedo.nome}</div>
                                    <div className="modulo_brinquedo">
                                        <img alt={brinquedo.nome} className="icone_brinquedo" src={"http://localhost:9000/imagem/"+brinquedo.imagem} height="40px"  />
                                    </div>
                                </div>
                            </div>)
                        }
                }, i)
                
            }
        </div>
    )
}

const MensagemDeTopo = (props) => {
    return(
        <center>{props.mensagemDeTopo}</center>
    )
}


function TelaEventos(){

    const {conteudoDaTela, eventos, setEventos} = useContext(ContextoGlobal);

    function montarExibicaoEventos(){
        console.log(eventos);
    }

    useEffect(() => {
        async function listarEventos(){
            montarExibicaoEventos(await FetchApi.consultaGet('/eventos').evento);
        }      
        listarEventos();

    }, []);
    
    return(
        <div>
            < MensagemDeTopo mensagemDeTopo={ conteudoDaTela.mensagemDeTopo } />
        </div>
    );
}

export default TelaEventos;
